      if (regex && tag) {
        config.capture_rules.push({
          enabled: enabled,
          regex: regex,
          tag: tag,
          updateMode: updateMode,
          range: range,
        });
      }
    });

    SillyTavern.extensionSettings[extensionName] = config;
    SillyTavern.saveSettingsDebounced();
    toastr.info('Lưu cấu hình thành công!');
  });
}

