        />
        <span class="zhino-setting-desc">tầng tự động kích hoạt</span>
      </div>
    </div>

    \x3c!-- Thiết lập người dùng (đa cấu hình) --\x3e
    <div class="zhino-section">
      <div class="zhino-section-header">
        <div class="zhino-section-title">Thiết lập người dùng</div>
        <button class="zhino-btn-sm" @click="isAddingPersona = !isAddingPersona">
          {{ isAddingPersona ? 'Hủy' : '+ Tạo mới' }}
        </button>
      </div>

      \x3c!-- Nhập thiết lập mới --\x3e
      <div v-if="isAddingPersona" class="zhino-add-persona">
        <input
          v-model="newPersonaName"
          class="zhino-input"
          placeholder="Tên thiết lập (VD: Nhân vật thường ngày, Nhân vật chiến đấu)"
          @keyup.enter="addPersona"
        />
        <button class="zhino-btn-sm zhino-btn-save" @click="addPersona">Tạo</button>
      </div>

      \x3c!-- Danh sách thiết lập --\x3e
      <div v-if="store.personas.length === 0" class="zhino-empty-hint">
        Tạm thời chưa có thiết lập, nhấp vào"+ Tạo mới"Tạo cái đầu tiên
      </div>
      <div v-else class="zhino-persona-list">
        <div
          v-for="p in store.personas"
          :key="p.id"
          class="zhino-persona-item"
          :class="{ active: store.activePersonaId === p.id }"
          @click="switchPersona(p.id)"
        >
          <div class="zhino-persona-item-left">
            <span v-if="renamingId !== p.id" class="zhino-persona-name">{{ p.name || 'Chưa đặt tên' }}</span>
            <input
              v-else
              v-model="renamingName"
              class="zhino-input zhino-input-inline"
              @keyup.enter="confirmRename"
              @blur="confirmRename"
              @click.stop
            />
            <span v-if="store.activePersonaId === p.id" class="zhino-persona-badge">Kích hoạt</span>
          </div>
          <div class="zhino-persona-item-right" @click.stop>
            <button class="zhino-btn-xs" @click="startRename(p.id, p.name)">Đổi tên</button>
            <button class="zhino-btn-xs zhino-btn-danger" @click="removePersona(p.id)">Xóa</button>
          </div>
        </div>
      </div>

      \x3c!-- Chỉnh sửa thiết lập đang kích hoạt --\x3e
      <template v-if="store.persona.id">
        <div class="zhino-persona-edit-header">
          Chỉnh sửa: {{ store.persona.name || 'Chưa đặt tên' }}
        </div>
        <textarea
          v-model="editingPersona"
          class="zhino-textarea"
          rows="5"
          placeholder="Điền thiết lập nhân vật của bạn (tính cách, hành vi chung, phong cách nói chuyện, v.v.)"
        />
        <div class="zhino-btn-row">
          <button class="zhino-btn-sm" @click="savePersonaOnly">Chỉ lưu</button>
          <button
            class="zhino-btn-sm zhino-btn-save"
            :disabled="isAnalyzing || !editingPersona.trim()"
            @click="saveAndAnalyzePersona"
          >
            {{ isAnalyzing ? 'Đang phân tích...' : 'Lưu và phân tích' }}
          </button>
        </div>
        <div v-if="store.persona.analyzedProfile" class="zhino-profile-preview">
          <div class="zhino-detail-label">Kết quả phân tích (có thể chỉnh sửa trực tiếp):</div>
          <textarea
            class="zhino-textarea"
            rows="6"
            :value="store.persona.analyzedProfile"
            @change="store.updatePersonaProfile(($event.target as HTMLTextAreaElement).value)"
          />
        </div>
      </template>
    </div>

    \x3c!-- Kiểm tra mô hình --\x3e
    <div class="zhino-section">
      <div class="zhino-section-title">Kiểm tra mô hình</div>
      <div class="zhino-info-row">
        <span class="zhino-info-label">Mô hình hiện tại:</span>
        <span class="zhino-info-value">{{ currentModel || 'Chưa phát hiện' }}</span>
      </div>
      <div v-if="isClaudeModel" class="zhino-warning">
        Đã phát hiện Claude mô hình, đã tự động điều chỉnh prefill Chiến lược (điều cuối cùng assistant prefill → system）
      </div>
    </div>


    \x3c!-- Quản lý dữ liệu --\x3e
    <div class="zhino-section">
      <div class="zhino-section-title">Quản lý dữ liệu</div>
      <div class="zhino-btn-row">
        <button class="zhino-btn-sm" @click="exportData">Xuất dữ liệu</button>
        <button class="zhino-btn-sm" @click="showImport = !showImport">Nhập dữ liệu</button>
        <button class="zhino-btn-sm zhino-btn-danger" @click="clearChatData">Xóa dữ liệu trò chuyện</button>
        <button class="zhino-btn-sm zhino-btn-danger" @click="clearAllData">Xóa tất cả</button>
      </div>
      <template v-if="showImport">
        <textarea
          v-model="importInput"
          class="zhino-textarea"
          rows="4"
          placeholder="Dán dữ liệu đã xuất JSON Dữ liệu"
        />
        <button class="zhino-btn-sm zhino-btn-save" @click="importData">Xác nhận nhập</button>
      </template>
    </div>
  </div>
