                rain: { dawn: 'linear-gradient(180deg, #2C3A47 0%, #465563 100%)', day: 'linear-gradient(180deg, #4A5B6E 0%, #6B7D91 100%)', dusk: 'linear-gradient(180deg, #24303E 0%, #3B4756 100%)', night: 'linear-gradient(180deg, #0E1621 0%, #1A2534 100%)' },
