        // ============ Tải tài nguyên Leaflet ============
        function loadLeafletResources(iframeDoc, callback) {
            // Kiểm tra xem đã tải chưa
            if (iframeDoc.getElementById('leaflet-css')) {
                callback();
                return;
            }

            // Tải CSS
            const css = iframeDoc.createElement('link');
            css.id = 'leaflet-css';
            css.rel = 'stylesheet';
            css.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css';
            iframeDoc.head.appendChild(css);

            // Tải JS
            const script = iframeDoc.createElement('script');
            script.id = 'leaflet-js';
            script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
            script.onload = callback;
            iframeDoc.head.appendChild(script);
        }

        // ============ Khởi tạo bản đồ ============
        function initMap(iframeDoc, iframeWindow) {
            const container = iframeDoc.getElementById('worldmap-container');
            if (!container) return;

            // Tạo div bản đồ
            const mapDiv = iframeDoc.createElement('div');
            mapDiv.id = 'leaflet-map';
            mapDiv.style.cssText = 'width:100%;height:100%';
            container.appendChild(mapDiv);

            // Khởi tạo bản đồ Leaflet
            const L = iframeWindow.L;
            if (!L) {
                console.error('[Bản đồ thế giới] Leaflet chưa được tải');
                return;
            }

            mapInstance = L.map('leaflet-map', {
                zoomControl: false
            }).setView([39.9042, 116.4074], 5); // Mặc định Bắc Kinh

            // Thêm layer OpenStreetMap
            L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                attribution: '© OpenStreetMap'
            }).addTo(mapInstance);

            // Thêm nút điều khiển thu phóng vào góc dưới bên phải
            L.control.zoom({ position: 'bottomright' }).addTo(mapInstance);

            // Nhấp vào bản đồ để chọn vị trí
            mapInstance.on('click', function (e) {
                setMarker(e.latlng.lat, e.latlng.lng, 'Vị trí tùy chỉnh', iframeDoc, L);
            });

            console.log('[Bản đồ thế giới] Khởi tạo bản đồ hoàn tất');
        }

        // ============ Đặt điểm đánh dấu ============
        function setMarker(lat, lng, name, iframeDoc, L) {
            if (!mapInstance || !L) return;

            // Xóa điểm đánh dấu cũ
            if (currentMarker) {
                mapInstance.removeLayer(currentMarker);
            }

            // Tạo điểm đánh dấu mới
            currentMarker = L.marker([lat, lng]).addTo(mapInstance);
            currentMarker.bindPopup(`<b>${name}</b><br>📍 ${lat.toFixed(4)}, ${lng.toFixed(4)}`).openPopup();

            // Cập nhật vị trí đã chọn
            selectedLocation = { name, lat, lng };

            // Hiển thị thanh thông tin
            const infoBar = iframeDoc.getElementById('worldmap-info-bar');
            const locationName = iframeDoc.getElementById('worldmap-location-name');
            const coords = iframeDoc.getElementById('worldmap-coords');

            if (infoBar) infoBar.style.display = 'block';
            if (locationName) locationName.textContent = name;
            if (coords) coords.textContent = `📍 ${lat.toFixed(4)}, ${lng.toFixed(4)}`;

            // Di chuyển bản đồ đến vị trí điểm đánh dấu
            mapInstance.setView([lat, lng], Math.max(mapInstance.getZoom(), 10));
        }

        // ============ Tìm kiếm địa điểm (Nominatim API) ============
        async function searchLocation(query, iframeDoc, iframeWindow) {
            const resultsDiv = iframeDoc.getElementById('worldmap-search-results');
            if (!resultsDiv) return;

            resultsDiv.innerHTML = '<div style="padding:12px;text-align:center;color:#666">Đang tìm kiếm...</div>';
            resultsDiv.style.display = 'block';

            try {
                const response = await fetch(
                    `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=5`,
                    { headers: { 'Accept-Language': 'zh-CN,zh,en' } }
                );
                const data = await response.json();

                if (data.length === 0) {
                    resultsDiv.innerHTML = '<div style="padding:12px;text-align:center;color:#999">Không tìm thấy kết quả</div>';
                    return;
                }

                resultsDiv.innerHTML = data.map(item => `
                    <div class="search-result-item" data-lat="${item.lat}" data-lng="${item.lon}" data-name="${item.display_name.split(',')[0]}" 
                         style="padding:10px 12px;border-bottom:1px solid #eee;cursor:pointer;font-size:13px">
                        <div style="font-weight:500;color:#333">${item.display_name.split(',')[0]}</div>
                        <div style="font-size:11px;color:#999;margin-top:2px">${item.display_name}</div>
                    </div>
                `).join('');

                // Gắn sự kiện nhấp chuột
                resultsDiv.querySelectorAll('.search-result-item').forEach(item => {
                    item.onclick = () => {
                        const lat = parseFloat(item.dataset.lat);
                        const lng = parseFloat(item.dataset.lng);
                        const name = item.dataset.name;
                        setMarker(lat, lng, name, iframeDoc, iframeWindow.L);
                        resultsDiv.style.display = 'none';
                        iframeDoc.getElementById('worldmap-search-input').value = name;
                    };
                });

            } catch (e) {
                console.error('[Bản đồ thế giới] Tìm kiếm thất bại:', e);
                resultsDiv.innerHTML = '<div style="padding:12px;text-align:center;color:#e53935">Tìm kiếm thất bại, vui lòng thử lại</div>';
            }
        }

        // ============ Lấy Danh_sách_khách_thuê (từ Trạng_thái MVU Zod) ============
        function getCompanionList() {
            try {
                const Mvu = window.parent.Mvu;
                if (Mvu && typeof Mvu.getMvuData === 'function') {
                    // Lấy ID tin nhắn mục tiêu
                    let targetMessageId = 'latest';
                    if (typeof window.parent.getLastMessageId === 'function') {
                        targetMessageId = window.parent.getLastMessageId();
                    } else {
                        const $ = window.parent.$;
                        if ($) {
                            const lastMes = $('#chat .mes').last();
                            if (lastMes.length) {
                                targetMessageId = lastMes.attr('mesid') || 'latest';
                            }
                        }
                    }

                    const result = Mvu.getMvuData({ type: 'message', message_id: targetMessageId });
                    if (result && result.stat_data) {
                        const tenantList = result.stat_data.Danh_sách_khách_thuê;
                        const roomList = result.stat_data.Căn_hộ?.Danh_sách_phòng;

                        // Xây dựng ánh xạ khách thuê -> phòng (Tra ngược từ trường Người_ở của phòng, hỗ trợ ở ghép phân cách bằng dấu phẩy ngược)
                        const tenantRoomMap = {};
                        if (roomList && typeof roomList === 'object') {
                            for (const [roomKey, roomData] of Object.entries(roomList)) {
                                const occupant = roomData?.Người_ở;
                                if (occupant && occupant !== '无') {
                                    const roomName = roomData?.Tên || roomKey;
                                    const floor = roomData?.Tầng || '';
                                    const displayName = roomName !== roomKey ? roomName : `${floor}`;
                                    // Hỗ trợ ở ghép: trường Người_ở có thể là định dạng "Trương Tiểu Tuyết、Lâm Thi Hàm"
                                    const names = occupant.split('、').map(s => s.trim()).filter(Boolean);
                                    for (const name of names) {
                                        if (name !== '<user>') tenantRoomMap[name] = displayName;
                                    }
                                }
                            }
                        }

                        if (tenantList && typeof tenantList === 'object') {
                            return Object.entries(tenantList).map(([name, data]) => ({
                                id: name,
                                name: name,
                                room: tenantRoomMap[name] || 'Chưa phân phòng'
                            }));
                        }
                    }
                }
            } catch (e) {
                console.log('[Bản đồ thế giới] Không thể lấy Danh_sách_khách_thuê MVU Zod:', e);
            }

            // Trả về mảng rỗng khi không có dữ liệu
            return [];
        }

        // ============ Trạng_thái chọn nhiều tạm thời ============
        let tempSelectedCompanions = [];

        // ============ Hiển thị chọn người đi cùng (Hỗ trợ chọn nhiều) ============
        function showCompanionModal(iframeDoc, isRefresh = false) {
            const modal = iframeDoc.getElementById('worldmap-companion-modal');
            const listDiv = iframeDoc.getElementById('worldmap-companion-list');
            if (!modal || !listDiv) return;

            const companions = getCompanionList();

            // Chỉ đặt lại lựa chọn tạm thời khi mở lần đầu, giữ nguyên Trạng_thái khi làm mới
            if (!isRefresh) {
                tempSelectedCompanions = [...selectedCompanions];
            }

            if (companions.length === 0) {
                listDiv.innerHTML = '<div style="padding:20px;text-align:center;color:#999">Tạm thời chưa có khách thuê để chọn</div>';
            } else {
                listDiv.innerHTML = companions.map(c => {
                    const isSelected = tempSelectedCompanions.some(s => s.id === c.id);
                    return `
                    <div class="companion-item" data-id="${c.id}" data-name="${c.name}" 
                         style="padding:12px;border:2px solid ${isSelected ? '#43a047' : '#ddd'};border-radius:8px;margin-bottom:8px;cursor:pointer;display:flex;align-items:center;gap:10px;background:${isSelected ? '#e8f5e9' : '#fff'};user-select:none">
                        <div style="width:40px;height:40px;background:${isSelected ? '#43a047' : '#e3f2fd'};border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:18px;color:${isSelected ? '#fff' : '#333'}">${isSelected ? '✓' : '👤'}</div>
                        <div style="flex:1">
                            <div style="font-weight:500">${c.name}</div>
                            <div style="font-size:12px;color:#999">${c.room}</div>
                        </div>
                    </div>
                `}).join('');

                // Gắn sự kiện chọn nhiều
                listDiv.querySelectorAll('.companion-item').forEach(item => {
                    item.addEventListener('click', function (e) {
                        e.preventDefault();
                        e.stopPropagation();

                        const id = this.dataset.id;
                        const name = this.dataset.name;
                        const index = tempSelectedCompanions.findIndex(s => s.id === id);

                        if (index >= 0) {
                            tempSelectedCompanions.splice(index, 1);
                        } else {
                            tempSelectedCompanions.push({ id, name });
                        }

                        // Làm mới hiển thị danh sách (Đánh dấu là chế độ làm mới)
                        showCompanionModal(iframeDoc, true);
                    });
                });
            }

            // Cập nhật số lượng đã chọn
            const countDiv = iframeDoc.getElementById('worldmap-selected-count');
            if (countDiv) {
                countDiv.textContent = `Đã chọn: ${tempSelectedCompanions.length} người`;
            }

            modal.style.display = 'flex';
        }

        // ============ Cập nhật hiển thị nút người đi cùng ============
        function updateCompanionButton(iframeDoc) {
            const btn = iframeDoc.getElementById('worldmap-companion-btn');
            if (!btn) return;

            if (selectedCompanions.length === 0) {
                btn.textContent = '👥 Chọn người đi cùng';
            } else if (selectedCompanions.length === 1) {
                btn.textContent = `👥 ${selectedCompanions[0].name}`;
            } else {
                btn.textContent = `👥 ${selectedCompanions.length} người đi cùng`;
            }
        }

        // ============ Thực thi xuất phát du lịch ============
        function goTravel(iframeDoc) {
            if (!selectedLocation) {
                if (window.parent.toastr) window.parent.toastr.warning('Vui lòng chọn đích đến trước');
                return;
            }

            const destination = selectedLocation.name;
            const coords = `(${selectedLocation.lat.toFixed(4)}, ${selectedLocation.lng.toFixed(4)})`;

            // Xây dựng mô tả chuyến đi (Hỗ trợ nhiều người đi cùng)
            let travelText;
            if (selectedCompanions.length === 0) {
                travelText = `Tôi đã đi một mình đến ${destination}${coords}`;
            } else if (selectedCompanions.length === 1) {
                travelText = `Tôi đã đưa ${selectedCompanions[0].name} cùng đi đến ${destination}${coords}`;
            } else {
                const names = selectedCompanions.map(c => c.name).join('、');
                travelText = `Tôi đã đưa ${names} cùng đi đến ${destination}${coords}`;
            }

            try {
                const stDoc = window.parent.document;
                const textarea = stDoc.getElementById('send_textarea');
                if (textarea) {
                    textarea.value = travelText;
                    textarea.dispatchEvent(new Event('input', { bubbles: true }));

                    if (window.parent.toastr) {
                        window.parent.toastr.success(`✈️ Đã điền thông tin chuyến đi`);
                    }

                    // Đóng APP và điện thoại
                    closeApp();
                    window.parent.PhoneSystem.goHome();

                    const container = stDoc.getElementById('tavern-phone-system-container');
                    const overlay = stDoc.getElementById('tavern-phone-system-overlay');
                    if (container) container.classList.remove('show');
                    if (overlay) overlay.classList.remove('show');
                    window.parent.PhoneSystem.isOpen = false;
                }
            } catch (e) {
                console.error('[Bản đồ thế giới] Điền thất bại:', e);
            }
        }

        // ============ Xử lý khi mở APP ============
        function openApp() {
            console.log('[Bản đồ thế giới] openApp được gọi');

            const phoneSystem = window.parent.PhoneSystem;
            if (!phoneSystem || !phoneSystem.iframeWindow) {
                setTimeout(openApp, 200);
                return;
            }

            const iframeWindow = phoneSystem.iframeWindow;
            let iframeDoc;
            try {
                iframeDoc = iframeWindow.document;
            } catch (e) {
                console.error('[Bản đồ thế giới] Không thể truy cập iframeDoc:', e);
                return;
            }

            // Ẩn trang chủ
            const homeScreen = iframeDoc.getElementById('home-screen');
            if (homeScreen) homeScreen.style.display = 'none';

            // Lấy app-container
            let appContainer = iframeDoc.getElementById('app-container');
            if (!appContainer) {
                const screen = iframeDoc.querySelector('.screen');
                if (screen) {
                    appContainer = iframeDoc.createElement('div');
                    appContainer.id = 'app-container';
                    appContainer.style.cssText = 'position:absolute;top:0;left:0;width:100%;height:100%;z-index:300;pointer-events:none';
                    screen.appendChild(appContainer);
                }
            }

            // Tiêm APP
            appContainer.innerHTML = generateAppHTML();
            appContainer.style.pointerEvents = 'auto';

            // Đặt lại Trạng_thái
            selectedLocation = null;
            selectedCompanions = [];
            tempSelectedCompanions = [];
            mapInstance = null;
            currentMarker = null;

            // Tải Leaflet và khởi tạo bản đồ
            loadLeafletResources(iframeDoc, () => {
                setTimeout(() => initMap(iframeDoc, iframeWindow), 100);
            });

            // Gắn sự kiện
            setTimeout(() => {
                // Nút trở về
                const backBtn = iframeDoc.getElementById('worldmap-back-btn');
                if (backBtn) {
                    backBtn.onclick = () => {
                        closeApp();
                        window.parent.PhoneSystem.goHome();
                    };
                }

                // Nút tìm kiếm
                const searchBtn = iframeDoc.getElementById('worldmap-search-btn');
                const searchInput = iframeDoc.getElementById('worldmap-search-input');
                if (searchBtn && searchInput) {
                    searchBtn.onclick = () => searchLocation(searchInput.value, iframeDoc, iframeWindow);
                    searchInput.onkeypress = (e) => {
                        if (e.key === 'Enter') searchLocation(searchInput.value, iframeDoc, iframeWindow);
                    };
                }

                // Nút người đi cùng
                const companionBtn = iframeDoc.getElementById('worldmap-companion-btn');
                if (companionBtn) {
                    companionBtn.onclick = () => showCompanionModal(iframeDoc);
                }

                // Đi một mình
                const companionAlone = iframeDoc.getElementById('worldmap-companion-alone');
                if (companionAlone) {
                    companionAlone.onclick = () => {
                        selectedCompanions = [];
                        tempSelectedCompanions = [];
                        iframeDoc.getElementById('worldmap-companion-modal').style.display = 'none';
                        updateCompanionButton(iframeDoc);
                    };
                }

                // Xác nhận chọn
                const companionConfirm = iframeDoc.getElementById('worldmap-companion-confirm');
                if (companionConfirm) {
                    companionConfirm.onclick = () => {
                        selectedCompanions = [...tempSelectedCompanions];
                        iframeDoc.getElementById('worldmap-companion-modal').style.display = 'none';
                        updateCompanionButton(iframeDoc);
                    };
                }

                // Nút xuất phát
                const goBtn = iframeDoc.getElementById('worldmap-go-btn');
                if (goBtn) {
                    goBtn.onclick = () => goTravel(iframeDoc);
                }

            }, 50);

            // Thanh Trạng_thái
            const statusBar = iframeDoc.getElementById('status-bar');
            if (statusBar) {
                statusBar.classList.remove('light');
                statusBar.classList.add('dark');
            }
        }

        // ============ Xử lý khi đóng APP ============
        function closeApp() {
            const phoneSystem = window.parent?.PhoneSystem;
            if (!phoneSystem?.iframeWindow) return;

            try {
                const iframeDoc = phoneSystem.iframeWindow.document;

                // Hủy phiên bản bản đồ
                if (mapInstance) {
                    mapInstance.remove();
                    mapInstance = null;
                }
                currentMarker = null;

                const appContainer = iframeDoc.getElementById('app-container');
                if (appContainer) {
                    appContainer.innerHTML = '';
                    appContainer.style.pointerEvents = 'none';
                }

                const homeScreen = iframeDoc.getElementById('home-screen');
                if (homeScreen) homeScreen.style.display = 'block';

                const statusBar = iframeDoc.getElementById('status-bar');
                if (statusBar) {
                    statusBar.classList.remove('dark');
                    statusBar.classList.add('light');
                }
            } catch (e) {
                console.error('[Bản đồ thế giới] closeApp thất bại:', e);
            }
        }

        // ============ Đăng ký APP ============
        window.parent.PhoneSystem.registerApp({
            id: APP_ID,
            name: APP_NAME,
            icon: APP_ICON,
            color: APP_COLOR,
            order: 6
        });

        // ============ Lắng nghe sự kiện ============
        window.parent.PhoneSystem.on('app-opened', function (data) {
            if (data.id === APP_ID) openApp();
        });

        window.parent.PhoneSystem.on('go-home', function () {
            closeApp();
        });

        console.log('[Bản đồ thế giới] Module đã tải xong');
    });
})();

/**
 * Điện thoại nhỏ - Module APP Tin tức (ĐỘC LẬP HOÀN TOÀN)
 * Đã Mod: Tách toàn bộ Logic khỏi Main Phone. App tự lo API, bối cảnh, lưu trữ và UI.
 * Đã Fix: Nút Làm mới hoạt động ổn định, lưu vĩnh viễn Tin Lạ vào gốc.
 */

(function () {
    'use strict';

    function waitForPhoneSystem(callback) {
        if (window.parent.PhoneSystem) {
            callback();
        } else {
            setTimeout(function () { waitForPhoneSystem(callback); }, 100);
        }
    }

    waitForPhoneSystem(function () {
        console.log('[APP Tin tức] Khởi tạo Module Độc lập...');

        const APP_ID = 'news';
        const APP_NAME = 'Tin tức hôm nay';
        const APP_ICON = '<img src="https://api.iconify.design/ri:newspaper-line.svg?color=white" style="width:70%;height:70%">';
        const APP_COLOR = 'linear-gradient(135deg, #ef4444, #dc2626)';
        const SPECIAL_NEWS_CHANCE = 0.25;

        // ============ TRÌNH QUẢN LÝ DỮ LIỆU ĐỘC LẬP CỦA APP ============
        const NewsManager = {
            data: { headlines: [], lastUpdate: null, isLoading: false },
            currentChatId: null,

            getChatId: function () {
                try {
                    var ctx = window.parent.SillyTavern?.getContext?.();
                    if (!ctx) return 'default';
                    if (typeof ctx.getCurrentChatId === 'function') return String(ctx.getCurrentChatId() || 'default');
                    if (ctx.chatId) return String(ctx.chatId);
                    return 'default';
                } catch (e) { return 'default'; }
            },

            getStorageKey: function () {
                return 'phone_news_standalone_' + this.getChatId();
            },

            loadLocalNews: function () {
                this.currentChatId = this.getChatId();
                try {
                    const saved = localStorage.getItem(this.getStorageKey());
                    if (saved) {
                        const parsed = JSON.parse(saved);
                        this.data.headlines = parsed.headlines || [];
                        this.data.lastUpdate = parsed.lastUpdate || null;
                    } else {
                        this.data.headlines = [];
                        this.data.lastUpdate = null;
                    }
                } catch (e) {
                    this.data.headlines = [];
                }
            },

            saveLocalNews: function () {
                try {
                    localStorage.setItem(this.getStorageKey(), JSON.stringify({
                        headlines: this.data.headlines,
                        lastUpdate: this.data.lastUpdate
                    }));
                    this.saveToSillyTavernVar();
                } catch (e) { console.error('[APP Tin tức] Lỗi lưu trữ:', e); }
            },

            saveToSillyTavernVar: function () {
                try {
                    if (this.data.headlines.length === 0) return;
                    var newsText = this.data.headlines.map(n => `【${n.tag}】${n.title}: ${n.summary}`).join('\n');
                    var command = '/setvar key=phone_news ' + newsText;
                    if (window.parent.executeSlashCommands) {
                        window.parent.executeSlashCommands(command);
                    } else if (window.parent.SillyTavern && window.parent.SillyTavern.getContext) {
                        window.parent.SillyTavern.getContext().executeSlashCommands?.(command);
                    }
                } catch (e) {}
            },

            getStoryContext: function () {
                try {
                    var ctx = window.parent.SillyTavern?.getContext?.();
                    if (!ctx || !ctx.chat || !Array.isArray(ctx.chat)) return '';
                    var recentMessages = ctx.chat.slice(-15);
                    var historyText = '';
                    for (var i = 0; i < recentMessages.length; i++) {
                        var msg = recentMessages[i];
                        if (msg && msg.mes) {
                            var cleanText = msg.mes
    .replace(/<!--[\s\S]*?-->/g, '') // Xóa triệt để các block comment HTML (Điểm neo, Số chữ...) nhiều dòng
    .replace(/<[^>]*>/g, '')         // Xóa các thẻ HTML thông thường (<br>, <i>...)
    .replace(/\{\{[^}]*\}\}/g, '')   // Xóa macro {{...}}
    .replace(/\[\[[^\]]*\]\]/g, '')  // Xóa macro [[...]]
    .trim();
                            if (cleanText) {
                                historyText += `${msg.is_user ? 'Người chơi' : 'Nhân vật'}: ${cleanText}\n`;
                            }
                        }
                    }
                    return historyText;
                } catch (e) { return ''; }
            }
        };

        // Khởi tạo data lần đầu
        NewsManager.loadLocalNews();

        // ============ LOGIC GỌI API ĐỘC LẬP ============
        async function fetchMainNews() {
            var settings = window.parent.PhoneSystem.getSettings();
            if (!settings.apiConfig || !settings.apiConfig.apiKey) throw new Error("Chưa cài đặt API Key trong điện thoại");

            const chatContext = NewsManager.getStoryContext();
            const systemPrompt = `Dựa vào bối cảnh câu chuyện dưới đây, tạo 3-5 tiêu đề tin tức ngắn gọn phản ánh thế giới trong truyện. Trả về đúng định dạng JSON: {"headlines":[{"tag":"...","title":"...","summary":"...","source":"...","time":"..."}]}`;
            const userPrompt = `Bối cảnh:\n${chatContext || 'Chưa có gì đặc biệt.'}\n\nTạo tin tức hôm nay.`;

            const result = await window.parent.PhoneSystem.callExternalAPI([
                { role: 'system', content: systemPrompt },
                { role: 'user', content: userPrompt }
            ]);

            if (result) {
                const jsonMatch = result.match(/\{[\s\S]*\}/);
                if (jsonMatch) {
                    const parsed = JSON.parse(jsonMatch[0]);
                    return parsed.headlines || [];
                }
            }
            throw new Error("Lỗi phân tích JSON từ AI");
        }

        async function fetchSpecialNewsItem() {
            try {
                const chatContext = NewsManager.getStoryContext();
                const systemPrompt = `Hệ thống tạo tin tức bí ẩn. Dựa vào bối cảnh, tạo 1 mẩu tin kỳ lạ, viễn tưởng hoặc thuyết âm mưu liên quan mờ nhạt đến nhân vật. Trả về JSON: {"tag":"Tin Lạ","title":"...","summary":"...","source":"...","time":"..."}`;
                const userPrompt = `Bối cảnh:\n${chatContext}\n\nTạo 1 tin đồn bí ẩn.`;

                const result = await window.parent.PhoneSystem.callExternalAPI([
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: userPrompt }
                ]);

                if (result) {
                    const jsonMatch = result.match(/\{[\s\S]*\}/);
                    if (jsonMatch) {
                        const parsed = JSON.parse(jsonMatch[0]);
                        parsed._isOtherWorld = true;
                        return parsed;
                    }
                }
                return null;
            } catch (e) { return null; }
        }

        async function refreshNews(iframeDoc) {
            if (NewsManager.data.isLoading) return;

            NewsManager.data.isLoading = true;
            const refreshBtn = iframeDoc.getElementById('news-refresh-btn');
            if (refreshBtn) {
                refreshBtn.disabled = true;
                refreshBtn.innerHTML = 'Đang tải...';
                refreshBtn.style.opacity = '0.6';
            }

            renderNewsList(iframeDoc); // Show loading

            try {
                // 1. Lấy tin tức chính
                let newHeadlines = await fetchMainNews();

                // 2. Chèn tin đặc biệt (Dị giới) nếu trúng tỷ lệ
                if (Math.random() < SPECIAL_NEWS_CHANCE) {
                    const specialNews = await fetchSpecialNewsItem();
                    if (specialNews) {
                        const insertAt = Math.floor(Math.random() * (newHeadlines.length + 1));
                        newHeadlines.splice(insertAt, 0, specialNews);
                    }
                }

                // 3. Cập nhật và Lưu
                if (newHeadlines && newHeadlines.length > 0) {
                    NewsManager.data.headlines = newHeadlines;
                    NewsManager.data.lastUpdate = new Date().toISOString();
                    NewsManager.saveLocalNews();
                    if (window.parent.toastr) window.parent.toastr.success("Đã cập nhật tin tức mới");
                }
            } catch (e) {
                console.error('[APP Tin tức] Lỗi làm mới:', e);
                if (window.parent.toastr) window.parent.toastr.error('Làm mới thất bại: ' + e.message);
            } finally {
                NewsManager.data.isLoading = false;
                if (refreshBtn) {
                    refreshBtn.disabled = false;
                    refreshBtn.innerHTML = 'Làm mới';
                    refreshBtn.style.opacity = '1';
                }
                renderNewsList(iframeDoc);
                updateTimeDisplay(iframeDoc);
            }
        }

        // ============ UI RENDER ============
        function generateHTML() {
            return `
            <div id="news-app" style="position:absolute;inset:0;background:#f5f7fa;display:flex;flex-direction:column;font-family:-apple-system,'SF Pro Text',sans-serif;color:#333;overflow:hidden;z-index:400">
                <div style="height:88px;display:flex;align-items:flex-end;padding:0 16px 12px;background:rgba(255,255,255,0.8);backdrop-filter:blur(20px);border-bottom:1px solid rgba(0,0,0,0.05);z-index:10;flex-shrink:0">
                    <div id="news-back-btn" style="color:#d32f2f;display:flex;align-items:center;gap:4px;cursor:pointer;width:60px">
                        <span style="font-size:18px">‹</span> Trở về
                    </div>
                    <div style="flex:1;text-align:center;font-weight:bold;font-size:17px">Tin tức hôm nay</div>
                    <div id="news-refresh-btn" style="width:60px;text-align:right;color:#d32f2f;font-size:16px;cursor:pointer">Làm mới</div>
                </div>
                <div id="news-update-time" style="padding:10px 16px;font-size:12px;color:#888;text-align:center;background:rgba(0,0,0,0.02)">
                    Nhấp vào góc trên bên phải để nhận tin mới
                </div>
                <div id="news-list" style="flex:1;overflow-y:auto;padding:16px;display:flex;flex-direction:column;gap:16px;-webkit-overflow-scrolling:touch">
                    </div>
                <div style="padding:12px;text-align:center;font-size:11px;color:#bbb;background:#f5f7fa">
                    Powered by AI · Standalone Module
                </div>
            </div>
            `;
        }

        function generateCSS() {
            return `
            <style id="news-app-styles">
                #news-app * { box-sizing: border-box; }
                #news-app button:active { opacity: 0.8; transform: scale(0.98); }
                .news-card {
                    background: #fff; border-radius: 12px; padding: 16px;
                    box-shadow: 0 2px 8px rgba(0,0,0,0.04); transition: transform 0.2s, box-shadow 0.2s;
                    border: 1px solid rgba(0,0,0,0.03); position: relative;
                }
                .news-card.other-world {
                    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
                    border: 1px solid rgba(138,43,226,0.3);
                    box-shadow: 0 2px 12px rgba(138,43,226,0.15);
                }
                .news-card.other-world .news-title { color: #e8d5ff; }
                .news-card.other-world .news-summary { color: #b8a0d0; }
                .news-card.other-world .news-meta { color: #7a6090; border-top-color: rgba(138,43,226,0.2); }
                .news-card:active { transform: scale(0.98); background: #f9f9f9; }
                .news-card.other-world:active { background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%); }
                .news-tag {
                    display: inline-block; padding: 4px 8px; border-radius: 6px; font-size: 11px;
                    font-weight: 600; margin-bottom: 8px; color: #fff;
                }
                .news-tag.breaking { background: #ff3b30; }
                .news-tag.local { background: #007aff; }
                .news-tag.social { background: #5856d6; }
                .news-tag.economy { background: #34c759; }
                .news-tag.weather { background: #5ac8fa; }
                .news-tag.otherworld { background: linear-gradient(135deg, #8a2be2, #4b0082); }
                .news-title { font-size: 18px; font-weight: 700; line-height: 1.35; color: #111; margin-bottom: 6px; letter-spacing: -0.3px; }
                .news-summary { font-size: 14px; line-height: 1.5; color: #666; margin-bottom: 12px; }
                .news-meta { display: flex; justify-content: space-between; font-size: 12px; color: #999; border-top: 1px solid #f0f0f0; padding-top: 10px; }
                .news-loading { text-align: center; padding: 40px; }
                .news-loading-spinner {
                    width: 32px; height: 32px; border: 3px solid rgba(211,47,47,0.2);
                    border-top-color: #d32f2f; border-radius: 50%; animation: news-spin 1s linear infinite; margin: 0 auto 16px;
                }
                @keyframes news-spin { to { transform: rotate(360deg); } }
            </style>
            `;
        }

        function renderNewsList(iframeDoc) {
            const listEl = iframeDoc.getElementById('news-list');
            if (!listEl) return;

            if (NewsManager.data.isLoading) {
                listEl.innerHTML = `
                    <div class="news-loading">
                        <div class="news-loading-spinner"></div>
                        <div style="color: #666;">Hệ thống AI đang phân tích bối cảnh...</div>
                    </div>
                `;
                return;
            }

            if (NewsManager.data.headlines.length === 0) {
                listEl.innerHTML = `
                    <div id="news-placeholder" style="text-align:center;padding:80px 20px;color:#999">
                        <div style="font-size:64px;margin-bottom:20px;opacity:0.3">📰</div>
                        <div style="font-size:16px;font-weight:500;margin-bottom:8px">Tạm thời chưa có tin tức</div>
                        <div style="font-size:14px">Nhấp vào "Làm mới" góc trên bên phải để nhận tin nóng</div>
                    </div>
                `;
                return;
            }

            const tagColors = {
                '突发': 'breaking', 'Đột phá': 'breaking',
                '本地': 'local', 'Địa phương': 'local',
                '社会': 'social', 'Xã hội': 'social',
                '经济': 'economy', 'Kinh tế': 'economy',
                '天气': 'weather', 'Thời tiết': 'weather',
                '异界': 'otherworld', 'Tin Lạ': 'otherworld'
            };

            listEl.innerHTML = NewsManager.data.headlines.map((news, index) => {
                const isOtherWorld = news._isOtherWorld === true;
                const tagClass = tagColors[news.tag] || 'local';
                const cardClass = isOtherWorld ? 'news-card other-world' : 'news-card';
                return `
                <div class="${cardClass}" data-index="${index}">
                    <span class="news-tag ${tagClass}">${news.tag || 'Thông tin'}</span>
                    <div class="news-title">${news.title}</div>
                    <div class="news-summary">${news.summary}</div>
                    <div class="news-meta">
                        <span>${news.source || 'Tin nhanh địa phương'}</span>
                        <span>${news.time || 'Vừa xong'}</span>
                    </div>
                </div>
                `;
            }).join('');
        }

        function updateTimeDisplay(iframeDoc) {
            const timeEl = iframeDoc.getElementById('news-update-time');
            if (timeEl && NewsManager.data.lastUpdate) {
                const time = new Date(NewsManager.data.lastUpdate);
                const hours = String(time.getHours()).padStart(2, '0');
                const minutes = String(time.getMinutes()).padStart(2, '0');
                timeEl.textContent = `Cập nhật lần cuối: ${hours}:${minutes}`;
            }
        }

        function initEvents(iframeDoc) {
            const backBtn = iframeDoc.getElementById('news-back-btn');
            if (backBtn) backBtn.onclick = () => window.parent.PhoneSystem.goHome();

            const refreshBtn = iframeDoc.getElementById('news-refresh-btn');
            if (refreshBtn) refreshBtn.onclick = () => refreshNews(iframeDoc);
        }

        // ============ VÒNG ĐỜI QUẢN LÝ APP ============
        function openApp() {
            const phoneSystem = window.parent.PhoneSystem;
            if (!phoneSystem || !phoneSystem.iframeWindow) {
                setTimeout(openApp, 200); return;
            }

            const iframeDoc = phoneSystem.iframeWindow.document;
            const homeScreen = iframeDoc.getElementById('home-screen');
            if (homeScreen) homeScreen.style.display = 'none';

            let appContainer = iframeDoc.getElementById('app-container');
            if (!appContainer) {
                const screen = iframeDoc.querySelector('.screen');
                if (screen) {
                    appContainer = iframeDoc.createElement('div');
                    appContainer.id = 'app-container';
                    appContainer.style.cssText = 'position:absolute;top:0;left:0;width:100%;height:100%;z-index:300;pointer-events:none';
                    screen.appendChild(appContainer);
                }
            }

            // Sync lại data mỗi khi mở app để đảm bảo lấy đúng của Character hiện tại
            const currentChatId = NewsManager.getChatId();
            if (currentChatId !== NewsManager.currentChatId) {
                NewsManager.loadLocalNews();
            }

            appContainer.innerHTML = generateCSS() + generateHTML();
            appContainer.style.pointerEvents = 'auto';

            setTimeout(() => {
                initEvents(iframeDoc);
                renderNewsList(iframeDoc);
                updateTimeDisplay(iframeDoc);
            }, 50);

            const statusBar = iframeDoc.getElementById('status-bar');
            if (statusBar) {
                statusBar.classList.remove('light');
                statusBar.classList.add('dark');
            }
        }

        function closeApp() {
            const phoneSystem = window.parent?.PhoneSystem;
            if (!phoneSystem?.iframeWindow) return;
            try {
                const iframeDoc = phoneSystem.iframeWindow.document;
                const appContainer = iframeDoc.getElementById('app-container');
                if (appContainer) {
                    appContainer.innerHTML = '';
                    appContainer.style.pointerEvents = 'none';
                }
                const homeScreen = iframeDoc.getElementById('home-screen');
                if (homeScreen) homeScreen.style.display = 'block';

                const statusBar = iframeDoc.getElementById('status-bar');
                if (statusBar) {
                    statusBar.classList.remove('dark');
                    statusBar.classList.add('light');
                }
            } catch (e) { }
        }

        // Đăng ký App vào Main Phone
        window.parent.PhoneSystem.registerApp({
            id: APP_ID, name: APP_NAME, icon: APP_ICON, color: APP_COLOR, order: 7
        });

        window.parent.PhoneSystem.on('app-opened', function (data) {
            if (data.id === APP_ID) openApp();
        });

        window.parent.PhoneSystem.on('go-home', function () {
            if (window.parent.PhoneSystem.currentApp === APP_ID || !window.parent.PhoneSystem.currentApp) closeApp();
        });

    });
})();

/**
 * Điện thoại nhỏ - Module APP YouTube (Virtual AI Tube)
 * Bản chuẩn: Ảnh random (Picsum) + Fix giao diện + Đọc Context gốc từ SillyTavern (Lọc Format) + Nâng giới hạn Context.
 */

(function () {
    'use strict';

    function waitForPhoneSystem(callback) {
        if (window.parent.PhoneSystem) {
            callback();
        } else {
            setTimeout(function () { waitForPhoneSystem(callback); }, 100);
        }
    }

    waitForPhoneSystem(function () {
        console.log('[APP Virtual Tube] Khởi tạo module');

        const APP_ID = 'youtube';
        const APP_NAME = 'YouTube';
        const APP_ICON = '<img src="https://api.iconify.design/logos:youtube-icon.svg" style="width:70%;height:70%">';
        const APP_COLOR = '#282828';

        let generatedVideos = [];
        let currentVideoIndex = -1;
        let isGenerating = false;

        // ============ ĐÃ CẬP NHẬT: Lấy bối cảnh gốc từ SillyTavern (Giống App Tin tức) ============
        function getStoryContext() {
            try {
                var ctx = window.parent.SillyTavern?.getContext?.();
                if (!ctx || !ctx.chat || !Array.isArray(ctx.chat)) return 'Chưa có bối cảnh.';

                var recentMessages = ctx.chat.slice(-15);
                var historyText = '';

                for (var i = 0; i < recentMessages.length; i++) {
                    var msg = recentMessages[i];
                    if (msg && msg.mes) {
                        var cleanText = msg.mes
                            .replace(/<!--[\s\S]*?-->/g, '') // Lọc điểm neo, số chữ (block comment)
                            .replace(/<[^>]*>/g, '')         // Lọc HTML
                            .replace(/\{\{[^}]*\}\}/g, '')   // Lọc macro {{}}
                            .replace(/\[\[[^\]]*\]\]/g, '')  // Lọc macro [[]]
                            .trim();

                        if (cleanText) {
                            historyText += `${msg.is_user ? 'Người chơi' : 'Nhân vật'}: ${cleanText}\n`;
                        }
                    }
                }

                // Mở rộng giới hạn lên 100000 ký tự theo yêu cầu cũ của YouTube
                if (historyText.length > 100000) {
                    historyText = "... " + historyText.substring(historyText.length - 100000);
                }

                return historyText || 'Chưa có bối cảnh.';
            } catch (e) { 
                console.warn('[APP Virtual Tube] Lỗi lấy lịch sử chat từ SillyTavern:', e);
                return 'Chưa có bối cảnh.'; 
            }
        }

        function extractJSON(text) {
            const match = text.match(/\{[\s\S]*\}/);
            if (match) {
                try { return JSON.parse(match[0]); } catch (e) { return null; }
            }
            return null;
        }

        // ============ API 1: Tạo danh sách Video ============
        async function fetchAIVideos(iframeDoc) {
            if (isGenerating) return;
            isGenerating = true;

            const btn = iframeDoc.getElementById('yt-generate-btn');
            if (btn) btn.innerHTML = '<span class="yt-spinner"></span> Đang quét mạng xã hội...';

            try {
                var settings = window.parent.PhoneSystem.getSettings();
                if (!settings.apiConfig || !settings.apiConfig.apiKey) throw new Error("Chưa cài API Key.");

                const context = getStoryContext();
                const systemPrompt = `Bạn là thuật toán đề xuất video. Dựa vào bối cảnh truyện dưới đây, tạo 4 video đang viral trên mạng liên quan đến sự kiện/nhân vật đó (tin tức, vlog, bóc phốt, v.v).
Trả về ĐÚNG JSON:
{"videos":[{"title":"Tên video giật tít","channel":"Tên kênh","views":"1.2 Tr lượt xem","time":"2 giờ trước"}]}`;

                const result = await window.parent.PhoneSystem.callExternalAPI([
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: `Bối cảnh:\n${context}\n\nTạo video.` }
                ]);

                const parsed = extractJSON(result);
                if (parsed && parsed.videos) {
                    const randomSession = Math.floor(Math.random() * 100000);
                    generatedVideos = parsed.videos.map((v, idx) => ({
                        ...v, 
                        seed: `scene_${randomSession}_${idx}`, 
                        detailsFetched: false, 
                        description: "", 
                        comments: []
                    }));
                    renderAIVideos(iframeDoc);
                }
            } catch (e) {
                if (window.parent.toastr) window.parent.toastr.error('Lỗi: ' + e.message);
            } finally {
                isGenerating = false;
                if (btn) btn.innerHTML = '🔄 Làm mới bảng tin';
            }
        }

        // ============ API 2: Tạo Chi tiết & Comments ============
        async function fetchVideoDetails(iframeDoc, index) {
            const video = generatedVideos[index];
            if (video.detailsFetched) {
                renderVideoDetail(iframeDoc, index);
                return;
            }

            iframeDoc.getElementById('yt-detail-content').innerHTML = `
                <div style="padding:40px; text-align:center; color:#aaa;">
                    <div class="yt-spinner" style="width:30px;height:30px;margin-bottom:15px;"></div>
                    <div>Đang tải dữ liệu và bình luận...</div>
                </div>`;

            try {
                const context = getStoryContext();
                const systemPrompt = `Bạn là hệ thống tạo chi tiết video. 
Dựa vào Tên Video và Bối cảnh truyện, viết 1 đoạn mô tả (Description) và 5 bình luận (Comments) từ cư dân mạng ảo (netizen). 
Bình luận cần chân thực, đa dạng (khen, chê, hóng hớt, tấu hài).
Trả về ĐÚNG JSON:
{"description":"Mô tả video...","comments":[{"user":"@username","text":"Nội dung cmt","likes":"124","time":"1 giờ trước"}]}`;

                const userPrompt = `Bối cảnh:\n${context}\n\nVideo: [${video.title}] của kênh [${video.channel}].\nTạo chi tiết.`;

                const result = await window.parent.PhoneSystem.callExternalAPI([
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: userPrompt }
                ]);

                const parsed = extractJSON(result);
                if (parsed) {
                    generatedVideos[index].description = parsed.description || "Không có mô tả.";
                    generatedVideos[index].comments = parsed.comments || [];
                    generatedVideos[index].detailsFetched = true;
                    renderVideoDetail(iframeDoc, index);
                }
            } catch (e) {
                iframeDoc.getElementById('yt-detail-content').innerHTML = `<div style="padding:20px;color:red;">Lỗi tải dữ liệu.</div>`;
            }
        }

        // ============ API 3: AI Rep Comment (Full ngữ cảnh) ============
        async function fetchCommentReply(iframeDoc, index, userText) {
            const video = generatedVideos[index];
            const btn = iframeDoc.getElementById('yt-submit-comment');
            if(btn) btn.innerHTML = '...';

            try {
                const context = getStoryContext();
                const systemPrompt = `Bạn là cộng đồng mạng. Một người dùng vừa bình luận vào video. Hãy tạo 1 hoặc 2 bình luận mới từ các netizen khác để hùa theo, cãi lại, hoặc rep trực tiếp comment đó. Phản ứng phải sát với nội dung video và bối cảnh.
Trả về ĐÚNG JSON:
{"comments":[{"user":"@random_user","text":"Nội dung rep...","likes":"12","time":"Vừa xong"}]}`;

                const userPrompt = `[BỐI CẢNH ROLEPLAY]\n${context}\n\n[THÔNG TIN VIDEO HIỆN TẠI]\nTiêu đề: ${video.title}\nKênh: ${video.channel}\nMô tả: ${video.description}\n\n[TÌNH HUỐNG]\nNgười chơi vừa comment: "${userText}"\n\nHãy hóa thân thành cộng đồng mạng để phản hồi lại.`;

                const result = await window.parent.PhoneSystem.callExternalAPI([
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: userPrompt }
                ]);

                const parsed = extractJSON(result);
                if (parsed && parsed.comments) {
                    generatedVideos[index].comments = [...parsed.comments, ...generatedVideos[index].comments];
                    renderComments(iframeDoc, index);
                }
            } catch (e) {} 
            finally {
                if(btn) btn.innerHTML = 'Gửi';
            }
        }

        // ============ RENDER: Danh sách Home ============
        function renderAIVideos(iframeDoc) {
            const listEl = iframeDoc.getElementById('yt-ai-list');
            if (!listEl) return;
            if (generatedVideos.length === 0) {
                listEl.innerHTML = `<div style="text-align:center;padding:40px;color:#888;">Chưa có video nào. Nhấn Làm mới.</div>`;
                return;
            }

            listEl.innerHTML = generatedVideos.map((vid, idx) => {
                const thumbUrl = `https://picsum.photos/seed/${vid.seed}/320/180`;

                return `
                <div class="yt-card" data-idx="${idx}">
                    <div class="yt-thumb" style="background-color:#222;">
                        <img src="${thumbUrl}" style="width:100%;height:100%;object-fit:cover;" loading="lazy">
                        <span class="yt-duration">${Math.floor(Math.random()*15)+1}:${String(Math.floor(Math.random()*60)).padStart(2,'0')}</span>
