        function renderHome() {
            if (!doc) return;
            var content = doc.getElementById('content'); if (!content) return;
            var colors = ['#f23d4e,#9e1b29', '#3e51b5,#283593', '#009688,#00695c', '#ff9800,#ef6c00', '#9c27b0,#6a1b9a'];
