    function executeRandomMove(doc) {
        const legalMoves = currentGame.moves();
        if (legalMoves.length === 0) return;

        const randomMove = legalMoves[Math.floor(Math.random() * legalMoves.length)];
        currentGame.move(randomMove);

        const msg = `*(Cười gượng)* Vì luật cờ rắc rối quá nên xin phép được đi bừa nước ${randomMove} nhé...`;
        chatHistory.push({ role: 'assistant', content: msg });
        appendChat(doc, 'oc', msg);

        drawBoard(doc);
        saveGameState();
        updateStatus(doc);
    }

    async function triggerAITurn(doc) {
        if (isProcessingAPI) return;
        isProcessingAPI = true;
        updateStatus(doc);

        const btnSend = doc.getElementById('btn-send-chat');
        if(btnSend) btnSend.style.opacity = '0.5';

        const isBlackTurnToMove = (!currentGame.game_over() && currentGame.turn() === 'b');
        const legalMoves = isBlackTurnToMove ? currentGame.moves() : [];
        const recentChats = chatHistory.slice(-12).map(m => m.role === 'user' ? `Player: ${m.content}` : `${currentOC.name}: ${m.content}`).join('\n') || '(Chưa có)';

        let promptBase = `Bây giờ bạn đóng vai ${currentOC.name}.\n`;
        promptBase += `Thông tin của bạn: ${currentOC.description}\nTính cách: ${currentOC.persona}\n\n`;
        promptBase += `BỐI CẢNH: Bạn đang chơi Cờ Vua qua mạng với Player. Bạn cầm quân ĐEN. Player cầm quân TRẮNG.\n`;
        promptBase += `Trạng thái bàn cờ hiện tại (FEN): ${currentGame.fen()}\n`;
        promptBase += `\nLịch sử trò chuyện gần đây:\n${recentChats}\n`;

        const PhoneSystem = window.parent.PhoneSystem;
        const settings = PhoneSystem.getSettings()?.apiConfig || {};

        let attempts = 0;
        const maxAttempts = 3;
        let chosenMove = null;
        let chosenChat = null;
        let moveSuccess = false;

        while (attempts < maxAttempts) {
            attempts++;

            let prompt = promptBase;
            if (isBlackTurnToMove) {
                prompt += `\n[HỆ THỐNG]: HIỆN TẠI ĐANG LÀ LƯỢT BẠN ĐI CỜ.\n`;
                prompt += `=== CHÚ Ý CỰC KỲ QUAN TRỌNG ===\n`;
                prompt += `Bạn CHỈ ĐƯỢC PHÉP copy chính xác 1 nước đi từ danh sách hợp lệ (SAN) dưới đây:\n`;
                prompt += `[ ${legalMoves.join(', ')} ]\n\n`;
                if (attempts > 1) {
                    prompt += `(Hệ thống cảnh báo: Lần thử trước bạn đã đưa ra nước đi sai luật. Hãy chọn thật cẩn thận nước đi CÓ TRONG DANH SÁCH)\n`;
                }
                prompt += `NHIỆM VỤ:\n1. Chọn MỘT nước đi trong danh sách trên.\n2. Viết câu thoại trò chuyện/trả lời Player.\n`;
                prompt += `BẮT BUỘC TRẢ VỀ ĐÚNG ĐỊNH DẠNG (Không thêm chữ thừa):\nMOVE: [nước đi bạn chọn]\nCHAT: [câu thoại của bạn]`;
            } else {
                prompt += `\n[HỆ THỐNG]: HIỆN TẠI LÀ LƯỢT PLAYER ĐI CỜ. Bạn đang chờ Player đi.\n`;
                prompt += `NHIỆM VỤ: Player vừa nhắn tin. Hãy phản hồi tự nhiên. KHÔNG đưa ra nước đi cờ lúc này.\n`;
                prompt += `BẮT BUỘC TRẢ VỀ ĐÚNG ĐỊNH DẠNG:\nCHAT: [câu thoại của bạn]`;
            }

            const apiMessages = [
                { role: 'system', content: JAILBREAK_LAYERS.layer1_identity },
                { role: 'system', content: JAILBREAK_LAYERS.layer2_nsfw },
                { role: 'user', content: prompt },
                { role: 'assistant', content: JAILBREAK_LAYERS.layer3_prefill }
            ];

            try {
                const responseText = await PhoneSystem.callExternalAPI(apiMessages, {
                    model: settings.model || 'gpt-3.5-turbo',
                    maxTokens: 350,
                    temperature: 0.7 
                });

                if (isBlackTurnToMove) {
                    const moveMatch = responseText.match(/MOVE:\s*([a-zA-Z0-9\-+#=]+)/i);
                    const chatMatch = responseText.match(/CHAT:\s*(.*)/is);

                    let parsedMove = moveMatch ? moveMatch[1].trim() : null;
                    chosenChat = chatMatch ? chatMatch[1].trim() : '(Lặng lẽ đi một nước cờ)';

                    if (parsedMove && legalMoves.includes(parsedMove)) {
                        chosenMove = parsedMove;
                        moveSuccess = true;
                        break; 
                    } else {
                        console.warn(`[Chess App] Retry ${attempts}/${maxAttempts}: AI đi nước sai luật (${parsedMove})`);
                    }
                } else {
                    // Chỉ chat, không cần validate move
                    const chatMatch = responseText.match(/CHAT:\s*(.*)/is);
                    chosenChat = chatMatch ? chatMatch[1].trim() : responseText.replace(/MOVE:.*$/m, '').trim();
                    moveSuccess = true;
                    break;
                }
            } catch (e) {
                console.error('[Chess App] Lỗi gọi API:', e);
                break; // Thoát vòng lặp nếu lỗi mạng/API
            }
        }

        // Xử lý kết quả sau vòng lặp
        if (isBlackTurnToMove) {
            if (moveSuccess && chosenMove) {
                currentGame.move(chosenMove);
                chatHistory.push({ role: 'assistant', content: chosenChat });
                appendChat(doc, 'oc', chosenChat);
                drawBoard(doc);
                saveGameState();
                isProcessingAPI = false;
                if(btnSend) btnSend.style.opacity = '1';
                updateStatus(doc);
            } else {
                // Thất bại sau 3 lần -> Hiển thị Popup xin phép
                isProcessingAPI = false;
                if(btnSend) btnSend.style.opacity = '1';
                updateStatus(doc);
                showRandomMovePrompt(doc); 
            }
        } else {
            if (chosenChat) {
                chatHistory.push({ role: 'assistant', content: chosenChat });
                appendChat(doc, 'oc', chosenChat);
                saveGameState();
            }
            isProcessingAPI = false;
            if(btnSend) btnSend.style.opacity = '1';
            updateStatus(doc);
        }
    }

    // ==================== KHỞI TẠO APP ====================
    function openChessApp() {
        const phoneSystem = window.parent.PhoneSystem;
        if (!phoneSystem || !phoneSystem.iframeWindow) return;

        const doc = phoneSystem.iframeWindow.document;
        doc.getElementById('home-screen').style.display = 'none';

        let appContainer = doc.getElementById('app-container');
        if (!appContainer) return;

        appContainer.innerHTML = '';
        appContainer.style.pointerEvents = 'auto';

        const statusBar = doc.getElementById('status-bar');
        if (statusBar) {
            statusBar.classList.remove('light');
            statusBar.classList.add('dark');
        }

        loadChessJS(doc, () => {
            renderCharacterSelect(appContainer, doc);
        });
    }

    const check = setInterval(() => {
        if (window.parent && window.parent.PhoneSystem) {
            clearInterval(check);
            const PhoneSystem = window.parent.PhoneSystem;

            PhoneSystem.registerApp({
                id: APP_ID,
                name: 'Cờ Vua',
                icon: '<img src="https://api.iconify.design/ri:vip-crown-fill.svg?color=white" style="width:65%;height:65%;">',
                color: 'linear-gradient(135deg, #795548, #3e2723)', 
                order: 13
            });

            PhoneSystem.on('app-opened', (data) => {
                if (data.id === APP_ID) openChessApp();
            });

            console.log('✅ APP Cờ Vua Cùng OC (Bản Tối Ưu Nước Đi) đã được tải!');
        }
    }, 100);

})();

